def on_node_click_treeFiles():
    node = treeFiles.get_selected()
    if node:
        update_file_list(node.tag)
        lblStatus.set_panel_text(0, node.text)

def on_node_expand_treeFiles():
    # Lazy load children
    node = treeFiles.get_selected()
    if node and node.tag:
        load_directory(node, node.tag)

def on_cell_click_gridFiles():
    row = gridFiles.selected_row
    if row >= 0 and row < len(gridFiles.grid_data):
        filename = gridFiles.grid_data[row][0]
        lblStatus.set_panel_text(0, f'Selected: {filename}')
